import React, { useEffect, useState } from 'react';
import { Box, Card, CardContent, Typography, CircularProgress } from '@mui/material';

export default function Record() {
  const [workReports, setWorkReports] = useState([]);
  const [loading, setLoading] = useState(true);

  // Fetch Data
  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('http://localhost:5000/work-reports');
        const data = await response.json();
        setWorkReports(data);
        setLoading(false);
      } catch (error) {
        console.error("Error fetching work reports:", error);
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  return (
    <Box sx={{ padding: 3, maxWidth: 1000, margin: 'auto' }}>
      <Typography variant="h4" sx={{ textAlign: 'center', marginBottom: 2 }}>
        Work Reports
      </Typography>

      {loading ? (
        <Box sx={{ textAlign: 'center', marginTop: 4 }}>
          <CircularProgress />
        </Box>
      ) : (
        <>
          {workReports.length > 0 ? (
            workReports.map((report) => (
              <Card key={report.id} sx={{ marginBottom: 2, padding: 2, boxShadow: 3 }}>
                <CardContent>
                  <Typography variant="h6" sx={{ fontWeight: 'bold' }}>
                    Machine Name: {report.machine_name}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    Date: {new Date(report.date).toLocaleDateString()}
                  </Typography>
                  <Typography variant="body2">
                    <strong>Nature of Complaint:</strong> {report.nature_of_complaint}
                  </Typography>
                  <Typography variant="body2">
                    <strong>Solution:</strong> {report.solution}
                  </Typography>
                  <Typography variant="body2">
                    <strong>In Time:</strong> {new Date(report.in_time).toLocaleTimeString()}
                  </Typography>
                  <Typography variant="body2">
                    <strong>Out Time:</strong> {new Date(report.out_time).toLocaleTimeString()}
                  </Typography>
                  <Typography variant="body2">
                    <strong>Status:</strong> {report.status}
                  </Typography>
                  <Typography variant="body2">
                    <strong>Assistant Name:</strong> {report.assistant_name}
                  </Typography>
                </CardContent>
              </Card>
            ))
          ) : (
            <Typography sx={{ textAlign: 'center', marginTop: 4 }}>
              No work reports found.
            </Typography>
          )}
        </>
      )}
    </Box>
  );
}
